"use strict";document.addEventListener("DOMContentLoaded",()=>{const contenidos=["cl-content-wpo","cl-content-ttfb","cl-content-http2","cl-content-dns","cl-content-gzip","cl-content-mail"],muestraSoloDivActual=idActual=>{contenidos.forEach(id=>{document.getElementById(id).style.display="none"}),document.getElementById(idActual).style.display="flex"};Object.entries({"cl-wpo":"cl-content-wpo","cl-ttfb":"cl-content-ttfb","cl-http2":"cl-content-http2","cl-dns":"cl-content-dns","cl-gzip":"cl-content-gzip","cl-mail":"cl-content-mail"}).forEach(([botonId,contenidoId])=>{document.getElementById(botonId).addEventListener("click",()=>{muestraSoloDivActual(contenidoId)})})});
